import React, { useEffect, useState } from "react";
import Navbar from "../components/Navbar";
import { getBookings } from "../services/api";
import { formatDateVN, formatTimeVN } from "../utils/format";

function AdminBookings() {
  const [bookings, setBookings] = useState([]);
  const [error, setError] = useState("");

  useEffect(() => {
    const fetchBookings = async () => {
      try {
        const data = await getBookings();
        setBookings(data);
      } catch (err) {
        setError(err.message);
      }
    };

    fetchBookings();
  }, []);

  return (
    <div>
      <Navbar />

      <div className="container page-section">
        <h1 className="section-title">Quản lý đặt sân</h1>
        <p className="section-subtitle">
          Theo dõi danh sách các lượt đặt sân đã được tạo trong hệ thống.
        </p>

        {error && <p className="error-text">{error}</p>}

        <div className="table-wrap">
          <table>
            <thead>
              <tr>
                <th>Mã</th>
                <th>Mã người dùng</th>
                <th>Mã sân</th>
                <th>Tên sân</th>
                <th>Ngày đặt</th>
                <th>Giờ bắt đầu</th>
                <th>Giờ kết thúc</th>
                <th>Trạng thái</th>
              </tr>
            </thead>

            <tbody>
              {bookings.map((booking) => (
                <tr key={booking.id}>
                  <td>{booking.id}</td>
                  <td>{booking.user_id ?? "-"}</td>
                  <td>{booking.field_id}</td>
                  <td>{booking.field_name || "-"}</td>
                  <td>{formatDateVN(booking.booking_date) || "-"}</td>
                  <td>{formatTimeVN(booking.start_time)}</td>
                  <td>{formatTimeVN(booking.end_time)}</td>
                  <td>{booking.status}</td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </div>
    </div>
  );
}

export default AdminBookings;
